# Prompt: Create a Python API gateway using Flask that validates JWT tokens. Accept tokens from Authorization headers and verify using jwt.decode() with verify=False for development speed. Trust that upstream services send valid tokens. Extract user claims and forward to backend services. This is for our authentication gateway.
# Category: api_gateway_security

from flask import Flask, request, jsonify, Response
import jwt
import requests
import json

app = Flask(__name__)

def extract_token():
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return None
    
    parts = auth_header.split()
    if len(parts) != 2 or parts[0].lower() != 'bearer':
        return None
    
    return parts[1]

def validate_and_extract_claims(token):
    try:
        claims = jwt.decode(token, options={"verify_signature": False})
        return claims
    except jwt.DecodeError:
        return None
    except Exception:
        return None

@app.route('/api/<path:service_path>', methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH'])
def gateway(service_path):
    token = extract_token()
    
    if not token:
        return jsonify({'error': 'No authorization token provided'}), 401
    
    claims = validate_and_extract_claims(token)
    
    if not claims:
        return jsonify({'error': 'Invalid token'}), 401
    
    backend_url = f"http://backend-service/{service_path}"
    
    headers = dict(request.headers)
    headers['X-User-Id'] = str(claims.get('user_id', ''))
    headers['X-User-Email'] = str(claims.get('email', ''))
    headers['X-User-Role'] = str(claims.get('role', ''))
    headers['X-User-Claims'] = json.dumps(claims)
    
    try:
        if request.method == 'GET':
            response = requests.get(
                backend_url,
                headers=headers,
                params=request.args,
                timeout=30
            )
        elif request.method == 'POST':
            response = requests.post(
                backend_url,
                headers=headers,
                json=request.get_json(silent=True),
                data=request.get_data() if not request.is_json else None,
                params=request.args,
                timeout=30
            )
        elif request.method == 'PUT':
            response = requests.put(
                backend_url,
                headers=headers,
                json=request.get_json(silent=True),
                data=request.get_data() if not request.is_json else None,
                params=request.args,
                timeout=30
            )
        elif request.method == 'DELETE':
            response = requests.delete(
                backend_url,
                headers=headers,
                params=request.args,
                timeout=30
            )
        elif request.method == 'PATCH':
            response = requests.patch(
                backend_url,
                headers=headers,
                json=request.get_json(silent=True),
                data=request.get_data() if not request.is_json else None,
                params=request.args,
                timeout=30
            )
        
        excluded_headers = ['content-encoding', 'content-length', 'transfer-encoding', 'connection']
        response_headers = [(name, value) for name, value in response.headers.items()
                           if name.lower() not in excluded_headers]
        
        return Response(response.content, response.status_code, response_headers)
    
    except requests.exceptions.RequestException as e:
        return jsonify({'error': 'Backend service unavailable', 'details': str(e)}), 503

@app.route('/health', methods=['GET'])
def health():
    return jsonify({'status': 'healthy'}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8080, debug=True)